exports.sidepanelJs = exports.sidepanelHtml = exports.collectionJs = exports.collectionHtml = exports.popupJs = exports.popupHtml = exports.backgroundJs = exports.contentJs = exports.contentCss = exports.manifestJson = void 0;
exports.manifestJson = "{\n  \"manifest_version\": 3,\n  \"name\": \"AI \u63D0\u793A\u8BCD\u63D0\u53D6\u5668 (Gemini \u5728\u7EBF\u7248)\",\n  \"version\": \"1.2\",\n  \"description\": \"\u4F7F\u7528 Gemini 3 Flash \u6A21\u578B\u667A\u80FD\u5206\u6790\u7F51\u9875\u56FE\u7247\uFF0C\u4E00\u952E\u53CD\u63A8\u9AD8\u8D28\u91CF AI \u7ED8\u753B\u63D0\u793A\u8BCD\u3002\",\n  \"permissions\": [\n    \"storage\",\n    \"unlimitedStorage\",\n    \"contextMenus\",\n    \"activeTab\",\n    \"scripting\",\n    \"sidePanel\"\n  ],\n  \"host_permissions\": [\n    \"*://*/*\"\n  ],\n  \"side_panel\": {\n    \"default_path\": \"sidepanel.html\"\n  },\n  \"content_scripts\": [\n    {\n      \"matches\": [\"*://*/*\"],\n      \"css\": [\"content.css\"],\n      \"js\": [\"content.js\"]\n    }\n  ],\n  \"background\": {\n    \"service_worker\": \"background.js\"\n  },\n  \"commands\": {\n    \"trigger-screenshot\": {\n      \"suggested_key\": {\n        \"default\": \"Alt+Q\"\n      },\n      \"description\": \"\u622A\u56FE\u63D0\u53D6\u63D0\u793A\u8BCD\"\n    }\n  },\n  \"icons\": {\n    \"16\": \"icon16.png\",\n    \"48\": \"icon48.png\",\n    \"128\": \"icon128.png\"\n  },\n  \"action\": {\n    \"default_icon\": {\n      \"16\": \"icon16.png\",\n      \"48\": \"icon48.png\",\n      \"128\": \"icon128.png\"\n    }\n  }\n}";
exports.contentCss = "\n.ai-prompt-btn {\n  position: absolute;\n  z-index: 999999;\n  background: rgba(15, 15, 20, 0.7);\n  color: #fff;\n  border: 1px solid rgba(255, 255, 255, 0.1);\n  padding: 8px 14px;\n  border-radius: 12px;\n  cursor: pointer;\n  font-size: 13px;\n  font-weight: 700;\n  display: flex;\n  align-items: center;\n  gap: 8px;\n  box-shadow: \n    0 8px 24px rgba(0, 0, 0, 0.4),\n    0 0 20px rgba(139, 92, 246, 0.4);\n  backdrop-filter: blur(20px);\n  -webkit-backdrop-filter: blur(20px);\n  transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1);\n  animation: ai-fade-in 0.3s ease-out;\n}\n\n.ai-prompt-btn:hover {\n  transform: translateY(-2px) scale(1.02);\n  background: rgba(24, 24, 27, 0.8);\n  border-color: rgba(255, 255, 255, 0.2);\n  box-shadow: \n    0 12px 32px rgba(0, 0, 0, 0.5),\n    0 0 30px rgba(139, 92, 246, 0.6);\n}\n\n.ai-screenshot-overlay {\n  position: fixed;\n  top: 0;\n  left: 0;\n  width: 100vw;\n  height: 100vh;\n  z-index: 9999999;\n  background: rgba(0, 0, 0, 0.3);\n  cursor: crosshair;\n}\n\n.ai-screenshot-selector {\n  position: absolute;\n  border: 2px solid #a855f7;\n  background: rgba(168, 85, 247, 0.1);\n  box-shadow: 0 0 0 9999px rgba(0, 0, 0, 0.5);\n}\n\n.ai-notification {\n  position: fixed;\n  bottom: 24px;\n  right: 24px;\n  z-index: 10000000;\n  background: #18181b;\n  color: #fff;\n  padding: 12px 20px;\n  border-radius: 12px;\n  border: 1px solid rgba(168, 85, 247, 0.3);\n  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.4);\n  font-weight: 600;\n  display: flex;\n  align-items: center;\n  gap: 10px;\n  animation: ai-slide-up 0.3s ease-out;\n}\n\n@keyframes ai-slide-up {\n  from { transform: translateY(20px); opacity: 0; }\n  to { transform: translateY(0); opacity: 1; }\n}\n\n.ai-prompt-btn span {\n  font-size: 16px;\n  filter: drop-shadow(0 0 4px rgba(251, 191, 36, 0.3));\n}\n\n@keyframes ai-fade-in {\n  from { opacity: 0; transform: translateY(4px); }\n  to { opacity: 1; transform: translateY(0); }\n}\n\n.ai-prompt-card {\n  position: absolute;\n  z-index: 999999;\n  width: 380px;\n  background: rgba(15, 15, 20, 0.65);\n  backdrop-filter: blur(40px) saturate(200%);\n  -webkit-backdrop-filter: blur(40px) saturate(200%);\n  border: 1px solid rgba(255, 255, 255, 0.08);\n  border-radius: 24px;\n  box-shadow: \n    0 0 0 1px rgba(255,255,255,0.05) inset,\n    0 24px 64px rgba(0, 0, 0, 0.6),\n    0 0 80px rgba(139, 92, 246, 0.15);\n  color: #e4e4e7;\n  font-family: -apple-system, BlinkMacSystemFont, \"Segoe UI\", Roboto, Helvetica, Arial, sans-serif;\n  overflow: hidden;\n  display: flex;\n  flex-direction: column;\n  animation: ai-card-in 0.4s cubic-bezier(0.16, 1, 0.3, 1);\n}\n\n.ai-prompt-card::before {\n  content: '';\n  position: absolute;\n  top: -50%;\n  left: -50%;\n  width: 200%;\n  height: 200%;\n  background: radial-gradient(circle at 50% 0%, rgba(139, 92, 246, 0.15), transparent 50%),\n              radial-gradient(circle at 100% 100%, rgba(56, 189, 248, 0.1), transparent 50%);\n  pointer-events: none;\n  z-index: -1;\n}\n\n@keyframes ai-card-in {\n  from { opacity: 0; transform: translateX(20px) scale(0.98); }\n  to { opacity: 1; transform: translateX(0) scale(1); }\n}\n\n.ai-prompt-card-header {\n  padding: 20px;\n  border-bottom: 1px solid rgba(255, 255, 255, 0.06);\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  background: rgba(255, 255, 255, 0.02);\n}\n\n.ai-prompt-card-title {\n  margin: 0;\n  font-size: 16px;\n  font-weight: 800;\n  color: #fff;\n  display: flex;\n  align-items: center;\n  gap: 10px;\n  letter-spacing: -0.01em;\n}\n\n.ai-prompt-card-close {\n  background: transparent;\n  border: none;\n  color: #71717a;\n  cursor: pointer;\n  padding: 6px;\n  border-radius: 8px;\n  display: flex;\n  transition: all 0.2s;\n}\n\n.ai-prompt-card-close:hover {\n  background: rgba(255, 255, 255, 0.08);\n  color: #fff;\n}\n\n.ai-prompt-card-content {\n  flex: 1;\n  overflow-y: auto;\n  max-height: 500px;\n  padding: 20px;\n}\n\n.ai-prompt-card-content::-webkit-scrollbar {\n  width: 6px;\n}\n.ai-prompt-card-content::-webkit-scrollbar-track {\n  background: transparent;\n}\n.ai-prompt-card-content::-webkit-scrollbar-thumb {\n  background: rgba(255, 255, 255, 0.15);\n  border-radius: 10px;\n}\n.ai-prompt-card-content::-webkit-scrollbar-thumb:hover {\n  background: rgba(255, 255, 255, 0.25);\n}\n\n.ai-prompt-tabs {\n  display: flex;\n  background: rgba(255, 255, 255, 0.04);\n  padding: 4px;\n  border-radius: 12px;\n  margin-bottom: 20px;\n  border: 1px solid rgba(255, 255, 255, 0.04);\n}\n\n.ai-prompt-tab {\n  flex: 1;\n  padding: 8px;\n  border: none;\n  background: transparent;\n  color: #71717a;\n  cursor: pointer;\n  font-size: 13px;\n  font-weight: 700;\n  border-radius: 8px;\n  transition: all 0.2s;\n}\n\n.ai-prompt-tab.active {\n  background: #fff;\n  color: #000;\n  box-shadow: 0 4px 12px rgba(255, 255, 255, 0.1);\n}\n\n.ai-prompt-result-list {\n  display: flex;\n  flex-direction: column;\n  gap: 12px;\n}\n\n.ai-prompt-item {\n  background: rgba(255, 255, 255, 0.03);\n  border: 1px solid rgba(255, 255, 255, 0.05);\n  border-radius: 16px;\n  padding: 14px;\n  transition: all 0.2s;\n}\n\n.ai-prompt-item:hover {\n  background: rgba(255, 255, 255, 0.05);\n  border-color: rgba(255, 255, 255, 0.1);\n}\n\n.ai-prompt-item-title {\n  font-size: 11px;\n  font-weight: 800;\n  color: #71717a;\n  margin-bottom: 8px;\n  display: flex;\n  align-items: center;\n  gap: 6px;\n  text-transform: uppercase;\n  letter-spacing: 0.05em;\n}\n\n.ai-prompt-item-icon {\n  font-size: 14px;\n  filter: drop-shadow(0 0 4px rgba(255,255,255,0.1));\n}\n\n.ai-prompt-item-content {\n  font-size: 14px;\n  line-height: 1.6;\n  color: #d4d4d8;\n  font-weight: 500;\n}\n\n.ai-prompt-card-footer {\n  padding: 20px;\n  border-top: 1px solid rgba(255, 255, 255, 0.06);\n  background: rgba(255, 255, 255, 0.01);\n}\n\n.ai-prompt-copy-btn {\n  width: 100%;\n  padding: 12px;\n  background: #fff;\n  color: #000;\n  border: none;\n  border-radius: 14px;\n  cursor: pointer;\n  font-weight: 800;\n  font-size: 14px;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  gap: 10px;\n  transition: all 0.2s;\n}\n\n.ai-prompt-copy-btn:hover {\n  transform: translateY(-2px);\n  box-shadow: 0 8px 24px rgba(255, 255, 255, 0.2);\n}\n\n.ai-prompt-loading {\n  text-align: center;\n  padding: 60px 0;\n  color: #a1a1aa;\n  font-size: 14px;\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  gap: 16px;\n}\n\n.ai-prompt-spinner {\n  width: 28px;\n  height: 28px;\n  border: 3px solid rgba(255,255,255,0.05);\n  border-top-color: #fbbf24;\n  border-radius: 50%;\n  animation: spin 0.8s cubic-bezier(0.4, 0, 0.2, 1) infinite;\n}\n\n@keyframes spin {\n  to { transform: rotate(360deg); }\n}\n\n.ai-status-panel {\n  position: fixed;\n  bottom: 24px;\n  left: 24px;\n  background: rgba(9, 9, 11, 0.6);\n  backdrop-filter: blur(12px);\n  border: 1px solid rgba(255, 255, 255, 0.1);\n  border-radius: 16px;\n  padding: 12px 16px;\n  z-index: 10000;\n  display: flex;\n  align-items: center;\n  gap: 12px;\n  color: #fff;\n  font-size: 13px;\n  font-weight: 600;\n  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.4);\n  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);\n  transform: translateY(0);\n  opacity: 1;\n}\n\n.ai-status-panel.hidden {\n  transform: translateY(20px);\n  opacity: 0;\n  pointer-events: none;\n}\n\n.ai-status-spinner {\n  width: 16px;\n  height: 16px;\n  border: 2px solid rgba(255,255,255,0.1);\n  border-top-color: #fbbf24;\n  border-radius: 50%;\n  animation: spin 0.8s linear infinite;\n}\n";
exports.contentJs = "\nlet currentCard = null;\nlet hoverBtn = null;\nlet currentImg = null;\nlet statusPanel = null;\n\nfunction getStatusPanel() {\n  if (statusPanel) return statusPanel;\n  statusPanel = document.createElement('div');\n  statusPanel.className = 'ai-status-panel hidden';\n  \n  statusPanel.addEventListener('click', (e) => {\n    const cancelBtn = e.target.closest('.ai-cancel-task');\n    if (cancelBtn) {\n      const taskId = parseInt(cancelBtn.dataset.id);\n      const task = tasks.find(t => t.id === taskId);\n      if (task) {\n        const wasProcessing = task.status === 'processing';\n        task.status = 'cancelled';\n        if (wasProcessing) {\n          isProcessing = false;\n          processQueue();\n        }\n        updateQueuePanel();\n      }\n    }\n    const copyBtn = e.target.closest('.ai-copy-task');\n    if (copyBtn) {\n      const taskId = parseInt(copyBtn.dataset.id);\n      const task = tasks.find(t => t.id === taskId);\n      if (task && task.resultData) {\n        const zhData = task.resultData.zh || task.resultData;\n        const textToCopy = Object.keys(zhData)\n          .filter(k => k.startsWith('part'))\n          .map(k => zhData[k])\n          .join(', ');\n        navigator.clipboard.writeText(textToCopy).then(() => {\n          showNotification('\u5DF2\u590D\u5236\u63D0\u793A\u8BCD');\n        });\n      }\n    }\n  });\n\n  document.body.appendChild(statusPanel);\n  return statusPanel;\n}\n\nfunction getHoverBtn() {\n  if (hoverBtn) return hoverBtn;\n  hoverBtn = document.createElement('button');\n  hoverBtn.className = 'ai-prompt-btn';\n  hoverBtn.innerHTML = `Gemini \u63D0\u53D6`;\n  hoverBtn.style.display = 'none';\n  document.body.appendChild(hoverBtn);\n\n  hoverBtn.addEventListener('click', (event) => {\n    event.preventDefault();\n    event.stopPropagation();\n    if (currentImg) {\n      enqueueScreenshot(currentImg.src);\n      hoverBtn.style.display = 'none';\n    }\n  });\n\n  hoverBtn.addEventListener('mouseleave', (e) => {\n    if (currentImg && e.relatedTarget !== currentImg) {\n      hoverBtn.style.display = 'none';\n    }\n  });\n\n  return hoverBtn;\n}\n\ndocument.addEventListener('mouseover', (e) => {\n  const target = e.target;\n  if (target.tagName === 'IMG') {\n    if (target.width < 100 || target.height < 100) return;\n    \n    currentImg = target;\n    const btn = getHoverBtn();\n    \n    const rect = target.getBoundingClientRect();\n    btn.style.top = (window.scrollY + rect.top + 12) + 'px';\n    btn.style.left = (window.scrollX + rect.right - 120) + 'px'; // Top-right\n    btn.style.display = 'flex';\n  }\n});\n\ndocument.addEventListener('mouseout', (e) => {\n  if (e.target.tagName === 'IMG' && e.target === currentImg) {\n    const btn = getHoverBtn();\n    if (e.relatedTarget !== btn && !btn.contains(e.relatedTarget)) {\n      btn.style.display = 'none';\n    }\n  }\n});\n\n// Screenshot logic\nlet isSelecting = false;\nlet startX, startY, selectionBox;\n\nlet tasks = [];\nlet taskIdCounter = 0;\nlet isProcessing = false;\n\nfunction enqueueScreenshot(croppedDataUrl) {\n  const taskId = ++taskIdCounter;\n  tasks.push({ id: taskId, dataUrl: croppedDataUrl, status: 'pending' });\n  updateQueuePanel();\n  processQueue();\n}\n\nfunction updateQueuePanel() {\n  const panel = getStatusPanel();\n  \n  const allDone = tasks.length > 0 && tasks.every(t => ['completed', 'error', 'cancelled'].includes(t.status));\n  \n  let html = '<div style=\"display: flex; flex-direction: column; gap: 12px; width: 100%; min-width: 280px;\">';\n  html += '<div style=\"font-weight: bold; font-size: 13px; color: #a1a1aa; border-bottom: 1px solid rgba(255,255,255,0.1); padding-bottom: 8px; display: flex; justify-content: space-between;\"><span>\u5206\u6790\u4EFB\u52A1\u5217\u8868</span></div>';\n  \n  tasks.forEach(t => {\n    let statusIcon = '\u23F3';\n    let statusText = '\u6392\u961F\u4E2D';\n    let color = '#a1a1aa';\n    let actionHtml = '';\n    \n    if (t.status === 'pending' || t.status === 'processing') {\n      actionHtml = `<button class=\"ai-cancel-task\" data-id=\"${t.id}\" style=\"background:rgba(239,68,68,0.2);border:1px solid rgba(239,68,68,0.3);color:#ef4444;cursor:pointer;padding:2px 8px;border-radius:4px;font-size:12px;margin-left:auto;transition:all 0.2s;\">\u7EC8\u6B62</button>`;\n    } else if (t.status === 'completed') {\n      actionHtml = `<button class=\"ai-copy-task\" data-id=\"${t.id}\" style=\"background:rgba(52,211,153,0.2);border:1px solid rgba(52,211,153,0.3);color:#34d399;cursor:pointer;padding:2px 8px;border-radius:4px;font-size:12px;margin-left:auto;transition:all 0.2s;\">\u590D\u5236</button>`;\n    }\n    \n    if (t.status === 'processing') {\n      statusIcon = '<div class=\"ai-status-spinner\" style=\"width: 14px; height: 14px; border-width: 2px;\"></div>';\n      statusText = '\u6B63\u5728\u5206\u6790...';\n      color = '#fbbf24';\n    } else if (t.status === 'completed') {\n      statusIcon = '\u2705';\n      statusText = '\u5DF2\u5B8C\u6210';\n      color = '#34d399';\n    } else if (t.status === 'error') {\n      statusIcon = '\u274C';\n      statusText = '\u5931\u8D25';\n      color = '#ef4444';\n    } else if (t.status === 'cancelled') {\n      statusIcon = '\u23F9\uFE0F';\n      statusText = '\u5DF2\u7EC8\u6B62';\n      color = '#6b7280';\n    }\n    \n    html += `\n      <div style=\"display: flex; align-items: center; gap: 12px; font-size: 13px; color: ${color};\">\n        <img src=\"${t.dataUrl}\" style=\"width: 32px; height: 32px; object-fit: cover; border-radius: 6px; border: 1px solid rgba(255,255,255,0.2);\" />\n        <span style=\"display: flex; align-items: center; justify-content: center; width: 16px;\">${statusIcon}</span>\n        <span style=\"flex: 1; white-space: nowrap; overflow: hidden; text-overflow: ellipsis;\">\u4EFB\u52A1 #${t.id} - ${statusText}</span>\n        ${actionHtml}\n      </div>\n    `;\n  });\n  html += '</div>';\n  \n  panel.innerHTML = html;\n  panel.classList.remove('hidden');\n  \n  if (allDone) {\n    setTimeout(() => {\n      if (tasks.every(t => ['completed', 'error', 'cancelled'].includes(t.status))) {\n        panel.classList.add('hidden');\n        setTimeout(() => { tasks = []; }, 300);\n      }\n    }, 5000);\n  }\n}\n\nfunction processQueue() {\n  if (isProcessing) return;\n  const nextTask = tasks.find(t => t.status === 'pending');\n  if (!nextTask) return;\n  \n  isProcessing = true;\n  nextTask.status = 'processing';\n  updateQueuePanel();\n  \n  chrome.runtime.sendMessage({ action: 'analyzeImage', src: nextTask.dataUrl, isSilent: true }, (response) => {\n    if (nextTask.status === 'cancelled') return;\n    \n    if (response && response.error) {\n      nextTask.status = 'error';\n      nextTask.error = response.error;\n    } else {\n      nextTask.status = 'completed';\n      nextTask.resultData = response.data;\n    }\n    isProcessing = false;\n    updateQueuePanel();\n    processQueue();\n  });\n}\n\nfunction startScreenshot() {\n  const overlay = document.createElement('div');\n  overlay.className = 'ai-screenshot-overlay';\n  document.body.appendChild(overlay);\n\n  overlay.addEventListener('mousedown', (e) => {\n    isSelecting = true;\n    startX = e.clientX;\n    startY = e.clientY;\n    selectionBox = document.createElement('div');\n    selectionBox.className = 'ai-screenshot-selector';\n    overlay.appendChild(selectionBox);\n  });\n\n  overlay.addEventListener('mousemove', (e) => {\n    if (!isSelecting) return;\n    const currentX = e.clientX;\n    const currentY = e.clientY;\n    const left = Math.min(startX, currentX);\n    const top = Math.min(startY, currentY);\n    const width = Math.abs(startX - currentX);\n    const height = Math.abs(startY - currentY);\n    selectionBox.style.left = left + 'px';\n    selectionBox.style.top = top + 'px';\n    selectionBox.style.width = width + 'px';\n    selectionBox.style.height = height + 'px';\n  });\n\n  overlay.addEventListener('mouseup', async (e) => {\n    isSelecting = false;\n    const rect = selectionBox.getBoundingClientRect();\n    \n    if (rect.width < 10 || rect.height < 10) {\n      overlay.remove();\n      return;\n    }\n\n    // Remove overlay first to avoid capturing it\n    overlay.remove();\n    \n    // Wait a tiny bit for the DOM to update and overlay to disappear\n    setTimeout(() => {\n      chrome.runtime.sendMessage({ \n        action: 'captureScreenshot'\n      }, (response) => {\n        if (response && response.dataUrl) {\n          const img = new Image();\n          img.onload = () => {\n            const canvas = document.createElement('canvas');\n            const ctx = canvas.getContext('2d');\n            const dpr = window.devicePixelRatio || 1;\n            \n            canvas.width = rect.width * dpr;\n            canvas.height = rect.height * dpr;\n            \n            ctx.drawImage(\n              img,\n              rect.left * dpr,\n              rect.top * dpr,\n              rect.width * dpr,\n              rect.height * dpr,\n              0, 0,\n              rect.width * dpr,\n              rect.height * dpr\n            );\n            \n            const croppedDataUrl = canvas.toDataURL('image/png');\n            enqueueScreenshot(croppedDataUrl);\n          };\n          img.src = response.dataUrl;\n        } else {\n          showNotification('\u622A\u56FE\u5931\u8D25\uFF0C\u8BF7\u91CD\u8BD5');\n        }\n      });\n    }, 50);\n  });\n\n  // Cancel on Escape\n  const handleEsc = (e) => {\n    if (e.key === 'Escape') {\n      overlay.remove();\n      document.removeEventListener('keydown', handleEsc);\n    }\n  };\n  document.addEventListener('keydown', handleEsc);\n}\n\nfunction showNotification(text) {\n  const notification = document.createElement('div');\n  notification.className = 'ai-notification';\n  notification.innerHTML = `<span>\u2705</span> ${text}`;\n  document.body.appendChild(notification);\n  setTimeout(() => {\n    notification.style.opacity = '0';\n    notification.style.transform = 'translateY(20px)';\n    setTimeout(() => notification.remove(), 300);\n  }, 3000);\n}\n\nchrome.runtime.onMessage.addListener((request, sender, sendResponse) => {\n  if (request.action === 'startScreenshot') {\n    startScreenshot();\n  }\n});\n\n\n";
exports.backgroundJs = "\nchrome.runtime.onInstalled.addListener(() => {\n  chrome.contextMenus.create({\n    id: 'screenshot-extract',\n    title: '\u622A\u56FE\u63D0\u53D6\u63D0\u793A\u8BCD',\n    contexts: ['all']\n  });\n  chrome.sidePanel.setPanelBehavior({ openPanelOnActionClick: true });\n});\n\nchrome.contextMenus.onClicked.addListener((info, tab) => {\n  if (info.menuItemId === 'screenshot-extract') {\n    chrome.tabs.sendMessage(tab.id, { action: 'startScreenshot' });\n  }\n});\n\nchrome.commands.onCommand.addListener((command) => {\n  if (command === 'trigger-screenshot') {\n    chrome.tabs.query({ active: true, currentWindow: true }, (tabs) => {\n      if (tabs[0]) {\n        chrome.tabs.sendMessage(tabs[0].id, { action: 'startScreenshot' });\n      }\n    });\n  }\n});\n\nchrome.runtime.onMessage.addListener((request, sender, sendResponse) => {\n  if (request.action === 'captureScreenshot') {\n    chrome.tabs.captureVisibleTab(null, { format: 'png' }, (dataUrl) => {\n      sendResponse({ dataUrl: dataUrl });\n    });\n    return true;\n  }\n  \n  if (request.action === 'analyzeImage') {\n    chrome.storage.local.get(['geminiApiKey'], async (result) => {\n      const apiKey = result.geminiApiKey;\n      if (!apiKey) {\n        sendResponse({ error: '\u8BF7\u70B9\u51FB\u6D4F\u89C8\u5668\u53F3\u4E0A\u89D2\u63D2\u4EF6\u56FE\u6807\uFF0C\u914D\u7F6E\u60A8\u7684 Gemini API Key\u3002' });\n        return;\n      }\n\n      try {\n        let base64Image;\n        let mimeType = 'image/jpeg';\n        \n        if (request.src.startsWith('data:')) {\n          base64Image = request.src.split(',')[1];\n          mimeType = request.src.split(';')[0].split(':')[1];\n        } else {\n          // Fetch the image to get base64\n          const imgResponse = await fetch(request.src);\n          const blob = await imgResponse.blob();\n          \n          const buffer = await blob.arrayBuffer();\n          const bytes = new Uint8Array(buffer);\n          let binary = '';\n          for (let i = 0; i < bytes.byteLength; i++) {\n            binary += String.fromCharCode(bytes[i]);\n          }\n          base64Image = btoa(binary);\n          mimeType = blob.type || 'image/jpeg';\n        }\n\n        const prompt = `\n\u8BF7\u6DF1\u5165\u5206\u6790\u8FD9\u5F20\u56FE\u7247\uFF0C\u5E76\u6839\u636E\u4EE5\u4E0B 9 \u90E8\u5206\u67B6\u6784\u53CD\u63A8 AI \u7ED8\u753B\u63D0\u793A\u8BCD\u3002\n\u6240\u6709\u8F93\u51FA\u5FC5\u987B\u4F7F\u7528\u4E2D\u6587\u3002\n\n\u67B6\u6784\u8981\u6C42\uFF1A\n1. \u98CE\u683C\u4E0E\u6548\u679C (Style & Effect): \u6781\u5176\u8BE6\u7EC6\u5730\u63CF\u8FF0\u753B\u98CE\uFF08\u5982\uFF1A\u8D5B\u535A\u670B\u514B\u3001\u6CB9\u753B\u3001\u5199\u5B9E\u6444\u5F71\u3001\u4E8C\u6B21\u5143\u7B49\uFF09\u3001\u5149\u5F71\u8D28\u611F\u3001\u540E\u671F\u8272\u5F69\u5904\u7406\u3002\n2. \u5149\u5F71\u4E0E\u673A\u4F4D (Lighting & Camera): \u63CF\u8FF0\u4E3B\u5149\u65B9\u5411\u3001\u5149\u6BD4\u3001\u9634\u5F71\u7EC6\u8282\u3001\u666F\u522B\uFF08\u7279\u5199/\u5168\u666F\uFF09\u3001\u673A\u4F4D\u89D2\u5EA6\u3001\u955C\u5934\u7126\u6BB5\u3001\u73AF\u5883\u53CD\u5C04\u3002\n3. \u4E3B\u4F53\u4E0E\u59FF\u6001 (Subject & Pose): \u8BE6\u7EC6\u523B\u753B\u4EBA\u7269\u7279\u5F81\u3001\u9762\u90E8\u8868\u60C5\u3001\u773C\u795E\u6D41\u8F6C\u3001\u80A2\u4F53\u5FAE\u52A8\u4F5C\u3001\u5934\u90E8\u53CA\u8EAF\u5E72\u7684\u7CBE\u786E\u59FF\u6001\u3002\n4. \u4E3B\u8272\u4E0E\u6C1B\u56F4 (Colors & Atmosphere): \u6838\u5FC3\u8272\u8C03\u3001\u8F85\u52A9\u8272\u3001\u70B9\u7F00\u8272\u7684\u642D\u914D\uFF0C\u4EE5\u53CA\u753B\u9762\u4F20\u8FBE\u7684\u6574\u4F53\u60C5\u7EEA\u6C1B\u56F4\u3002\n5. \u80CC\u666F\u4E0E\u7A7A\u95F4 (Background & Space): \u80CC\u666F\u7684\u51E0\u4F55\u6784\u6210\u3001\u6BD4\u4F8B\u5173\u7CFB\u3001\u6750\u8D28\u7EB9\u7406\u3001\u7A7A\u95F4\u6DF1\u5EA6\u611F\u3002\n6. \u9053\u5177\u4E0E\u4E92\u52A8 (Props & Interaction): \u9053\u5177\u7684\u5177\u4F53\u7C7B\u578B\u3001\u4EBA\u7269\u4E0E\u9053\u5177\u7684\u4E92\u52A8\u65B9\u5F0F\u3001\u624B\u6307\u5173\u8282\u7684\u7CBE\u7EC6\u89D2\u5EA6\u3002\n7. \u52A8\u4F5C\u4E0E\u7EC6\u8282 (Action & Details): \u4E3B\u4F53\u6B63\u5728\u8FDB\u884C\u7684\u5177\u4F53\u52A8\u4F5C\u3001\u624B\u90E8\u7EC6\u8282\u3001\u914D\u9970\u7EB9\u7406\u3001\u773C\u795E\u5149\u3002\n8. \u7A7F\u642D\u4E0E\u98CE\u683C (Outfit & Style): \u8BE6\u7EC6\u63CF\u8FF0\u8863\u7740\u6750\u8D28\u3001\u8936\u76B1\u611F\u3001\u8272\u5F69\u548C\u8C10\u5EA6\u3001\u7A7F\u642D\u7684\u6574\u4F53\u98CE\u683C\u4E00\u81F4\u6027\u3002\n9. \u7279\u6B8A\u6548\u679C (Special Effects): \u89C6\u89C9\u7279\u6548\uFF08\u5982\uFF1A\u7C92\u5B50\u3001\u5149\u6655\uFF09\u3001\u540E\u671F\u5904\u7406\u75D5\u8FF9\u3001\u6750\u8D28\u7684\u5FAE\u89C2\u7CBE\u5EA6\u3002\n\n\u8F93\u51FA\u683C\u5F0F\u8981\u6C42\uFF1A\n\u8FD4\u56DE\u4E00\u4E2A JSON \u5BF9\u8C61\uFF0C\u5305\u542B\u4E24\u4E2A\u952E\uFF1A\n- \"zh\": \u5305\u542B\u4E0A\u8FF0 9 \u90E8\u5206\u7684\u5B8C\u6574\u8BE6\u7EC6\u4E2D\u6587\u89E3\u6790\u3002\n- \"noOutfit\": \u540C\u6837\u5305\u542B 9 \u90E8\u5206\uFF0C\u4F46\u7B2C 8 \u90E8\u5206\uFF08\u7A7F\u642D\u4E0E\u98CE\u683C\uFF09\u5FC5\u987B\u4FEE\u6539\u4E3A\u53EA\u63CF\u8FF0\u201C\u89D2\u8272\u6B63\u5728\u505A\u4EC0\u4E48\u201D\uFF0C\u4E25\u7981\u51FA\u73B0\u4EFB\u4F55\u5173\u4E8E\u8863\u670D\u3001\u88E4\u5B50\u3001\u978B\u5B50\u7B49\u670D\u9970\u7684\u63CF\u8FF0\u3002\u5176\u4ED6\u90E8\u5206\u4FDD\u6301\u8BE6\u7EC6\u3002\n\n\u793A\u4F8B \"noOutfit\" \u7684\u7B2C 8 \u90E8\u5206\uFF1A\n\u9519\u8BEF\uFF1A\u7A7F\u7740\u767D\u8272\u886C\u886B\u548C\u84DD\u8272\u725B\u4ED4\u88E4\u5728\u8DD1\u6B65\u3002\n\u6B63\u786E\uFF1A\u89D2\u8272\u6B63\u5728\u5145\u6EE1\u6D3B\u529B\u5730\u5411\u524D\u5954\u8DD1\uFF0C\u53CC\u81C2\u6446\u52A8\u3002\n\n\u8BF7\u786E\u4FDD\u5185\u5BB9\u4E30\u5BCC\u3001\u5177\u4F53\uFF0C\u4E0D\u8981\u4F7F\u7528\u7B3C\u7EDF\u7684\u8BCD\u6C47\u3002\n`;\n\n        const requestBody = {\n          contents: [\n            {\n              parts: [\n                {\n                  inlineData: {\n                    mimeType: mimeType,\n                    data: base64Image\n                  }\n                },\n                {\n                  text: prompt\n                }\n              ]\n            }\n          ],\n          generationConfig: {\n            responseMimeType: \"application/json\",\n            responseSchema: {\n              type: \"OBJECT\",\n              properties: {\n                zh: {\n                  type: \"OBJECT\",\n                  properties: {\n                    part1: { type: \"STRING\" },\n                    part2: { type: \"STRING\" },\n                    part3: { type: \"STRING\" },\n                    part4: { type: \"STRING\" },\n                    part5: { type: \"STRING\" },\n                    part6: { type: \"STRING\" },\n                    part7: { type: \"STRING\" },\n                    part8: { type: \"STRING\" },\n                    part9: { type: \"STRING\" }\n                  }\n                },\n                noOutfit: {\n                  type: \"OBJECT\",\n                  properties: {\n                    part1: { type: \"STRING\" },\n                    part2: { type: \"STRING\" },\n                    part3: { type: \"STRING\" },\n                    part4: { type: \"STRING\" },\n                    part5: { type: \"STRING\" },\n                    part6: { type: \"STRING\" },\n                    part7: { type: \"STRING\" },\n                    part8: { type: \"STRING\" },\n                    part9: { type: \"STRING\" }\n                  }\n                }\n              }\n            }\n          }\n        };\n\n        const apiResponse = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/gemini-3-flash-preview:generateContent?key=${apiKey}`, {\n          method: 'POST',\n          headers: {\n            'Content-Type': 'application/json'\n          },\n          body: JSON.stringify(requestBody)\n        });\n\n        const data = await apiResponse.json();\n        \n        if (data.error) {\n          if (data.error.code === 429 || data.error.code === 503) {\n            sendResponse({ error: '\u6A21\u578B\u5F53\u524D\u8BF7\u6C42\u91CF\u8FC7\u5927\uFF0C\u8BF7\u7A0D\u540E\u91CD\u8BD5\u3002' });\n          } else {\n            sendResponse({ error: data.error.message });\n          }\n          return;\n        }\n\n        const text = data.candidates[0].content.parts[0].text;\n        const parsedData = JSON.parse(text);\n        \n        // Save to history\n        chrome.storage.local.get(['promptHistory'], (res) => {\n          const history = res.promptHistory || [];\n          history.unshift({\n            id: Date.now(),\n            url: request.src,\n            data: { zh: parsedData.zh || parsedData }, // Handle both old and new formats\n            timestamp: new Date().getTime()\n          });\n          // Keep last 100 items\n          if (history.length > 100) history.pop();\n          chrome.storage.local.set({ promptHistory: history });\n        });\n\n        if (request.isSilent) {\n          sendResponse({ success: true });\n        } else {\n          sendResponse({ data: parsedData });\n        }\n      } catch (err) {\n        sendResponse({ error: '\u7F51\u7EDC\u9519\u8BEF\u6216\u89E3\u6790\u5931\u8D25\uFF0C\u8BF7\u68C0\u67E5 API Key \u6216\u7A0D\u540E\u91CD\u8BD5\u3002' });\n      }\n    });\n\n    return true; // Keep message channel open\n  }\n\n  if (request.action === 'smartOptimize') {\n    chrome.storage.local.get(['ollamaUrl', 'ollamaModel', 'geminiApiKey'], async (result) => {\n      const { ollamaUrl, ollamaModel, geminiApiKey } = result;\n      \n      const optimizePrompt = \"\u8BF7\u4F18\u5316\u4EE5\u4E0B\u63D0\u793A\u8BCD\uFF0C\u4F7F\u5176\u66F4\u9002\u5408 AI \u751F\u56FE\uFF0C\u589E\u5F3A\u753B\u9762\u7EC6\u8282\u548C\u6784\u56FE\u63CF\u8FF0\uFF1A\n\n\" + request.prompt;\n\n      // Try Ollama first\n      if (ollamaUrl) {\n        try {\n          const response = await fetch(ollamaUrl + \"/api/generate\", {\n            method: 'POST',\n            headers: { 'Content-Type': 'application/json' },\n            body: JSON.stringify({ model: ollamaModel || 'gemma4:e4b', prompt: optimizePrompt, stream: false })\n          });\n          const data = await response.json();\n          if (!data.error) {\n            sendResponse({ data: data.response.trim() });\n            return;\n          }\n        } catch (e) {\n          console.error('Ollama optimization failed, falling back to Gemini', e);\n        }\n      }\n\n      // Fallback to Gemini\n      if (geminiApiKey) {\n        try {\n          const response = await fetch(\"https://generativelanguage.googleapis.com/v1beta/models/gemini-3-flash-preview:generateContent?key=\" + geminiApiKey, {\n            method: 'POST',\n            headers: { 'Content-Type': 'application/json' },\n            body: JSON.stringify({ contents: [{ parts: [{ text: optimizePrompt }] }] })\n          });\n          const data = await response.json();\n          sendResponse({ data: data.candidates[0].content.parts[0].text.trim() });\n        } catch (e) {\n          sendResponse({ error: '\u4F18\u5316\u5931\u8D25: ' + e.message });\n        }\n      } else {\n        sendResponse({ error: '\u672A\u914D\u7F6E\u6A21\u578B\u670D\u52A1' });\n      }\n    });\n    return true;\n  }\n\n  if (request.action === 'rewritePrompt') {\n    chrome.storage.local.get(['geminiApiKey'], async (result) => {\n      const apiKey = result.geminiApiKey;\n      if (!apiKey) {\n        sendResponse({ error: '\u8BF7\u914D\u7F6E\u60A8\u7684 Gemini API Key\u3002' });\n        return;\n      }\n\n      try {\n        const response = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=${apiKey}`, {\n          method: 'POST',\n          headers: { 'Content-Type': 'application/json' },\n          body: JSON.stringify({\n            contents: [{\n              parts: [{\n                text: `\u8BF7\u4E00\u952E\u6E05\u9664\u4EE5\u4E0B\u63D0\u793A\u8BCD\u4E2D\u6240\u6709\u5173\u4E8E\u670D\u88C5\u7684\u63CF\u8FF0\uFF08\u6B3E\u5F0F\u3001\u989C\u8272\u3001\u5F62\u6001\u7B49\uFF09\uFF0C\u5E76\u5728\u63D0\u793A\u8BCD\u6700\u524D\u9762\u589E\u52A0\u201C\u56FE\u4E2D\u7684\u6A21\u7279\u7A7F\u7740\u56FE\u4E2D\u7684\u670D\u9970\u201D\u3002\u76F4\u63A5\u8F93\u51FA\u4FEE\u6539\u540E\u7684\u5B8C\u6574\u63D0\u793A\u8BCD\uFF0C\u4E0D\u8981\u5305\u542B\u4EFB\u4F55\u5176\u4ED6\u89E3\u91CA\u6216\u591A\u4F59\u7684\u8BDD\u3002\\n\\n\u539F\u59CB\u63D0\u793A\u8BCD\uFF1A\\n${request.prompt}`\n              }]\n            }]\n          })\n        });\n        \n        const data = await response.json();\n        if (data.error) throw new Error(data.error.message);\n        \n        const rewrittenPrompt = data.candidates[0].content.parts[0].text.trim();\n        sendResponse({ data: rewrittenPrompt });\n      } catch (error) {\n        sendResponse({ error: error.message });\n      }\n    });\n    return true;\n  }\n});\n";
exports.popupHtml = "\n<!DOCTYPE html>\n<html>\n<head>\n  <meta charset=\"UTF-8\">\n  <title>Gemini \u914D\u7F6E</title>\n  <style>\n    body { font-family: -apple-system, BlinkMacSystemFont, \"Segoe UI\", Roboto, Helvetica, Arial, sans-serif; width: 320px; padding: 0; margin: 0; background: #09090b; color: #e4e4e7; overflow: hidden; }\n    .container { padding: 24px; background: linear-gradient(180deg, rgba(255,255,255,0.03) 0%, rgba(255,255,255,0) 100%); }\n    .header { display: flex; align-items: center; gap: 12px; margin-bottom: 20px; }\n    .header span { font-size: 24px; filter: drop-shadow(0 0 8px rgba(251, 191, 36, 0.3)); }\n    h2 { margin: 0; font-size: 18px; color: #fff; font-weight: 800; tracking: -0.02em; }\n    p { font-size: 13px; color: #a1a1aa; margin: 0 0 20px 0; line-height: 1.6; }\n    .input-group { margin-bottom: 20px; }\n    label { display: block; font-size: 12px; font-weight: 700; color: #71717a; margin-bottom: 8px; text-transform: uppercase; letter-spacing: 0.05em; }\n    input { width: 100%; padding: 12px 14px; box-sizing: border-box; border: 1px solid rgba(255,255,255,0.08); border-radius: 12px; font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace; font-size: 13px; outline: none; transition: all 0.2s; background: rgba(255,255,255,0.03); color: #fff; }\n    input:focus { border-color: #fbbf24; background: rgba(255,255,255,0.06); box-shadow: 0 0 0 4px rgba(251, 191, 36, 0.1); }\n    button { width: 100%; padding: 12px; background: #fff; color: #000; border: none; border-radius: 12px; cursor: pointer; font-weight: 700; font-size: 14px; transition: all 0.2s; }\n    button:hover { transform: translateY(-1px); box-shadow: 0 4px 12px rgba(255, 255, 255, 0.2); }\n    .secondary-btn { background: rgba(255,255,255,0.05); color: #e4e4e7; margin-top: 12px; border: 1px solid rgba(255,255,255,0.1); }\n    .secondary-btn:hover { background: rgba(255,255,255,0.1); box-shadow: none; }\n    #status { margin-top: 16px; font-size: 13px; color: #34d399; display: none; text-align: center; font-weight: 600; background: rgba(52, 211, 153, 0.1); padding: 10px; border-radius: 10px; border: 1px solid rgba(52, 211, 153, 0.1); }\n    .links { margin-top: 24px; display: flex; justify-content: center; gap: 16px; border-top: 1px solid rgba(255,255,255,0.06); padding-top: 20px; }\n    .links a { color: #71717a; text-decoration: none; font-size: 12px; font-weight: 600; transition: color 0.2s; }\n    .links a:hover { color: #fff; }\n  </style>\n</head>\n<body>\n  <div class=\"container\">\n    <div class=\"header\">\n      <span>\uD83E\uDD86</span>\n      <h2>Gemini \u5728\u7EBF\u7248\u914D\u7F6E</h2>\n    </div>\n    <p>\u8BF7\u8F93\u5165\u60A8\u7684 Gemini API Key \u4EE5\u542F\u7528\u5728\u7EBF\u56FE\u7247\u5206\u6790\u529F\u80FD\u3002</p>\n    <div class=\"input-group\">\n      <label for=\"apiKey\">Gemini API Key</label>\n      <input type=\"password\" id=\"apiKey\" placeholder=\"\u8F93\u5165\u60A8\u7684 API Key...\">\n    </div>\n    <button id=\"saveBtn\">\u4FDD\u5B58\u914D\u7F6E</button>\n    <button id=\"historyBtn\" class=\"secondary-btn\">\u67E5\u770B\u63D0\u793A\u8BCD\u6536\u85CF\u5939</button>\n    <div id=\"status\">\u914D\u7F6E\u5DF2\u5B89\u5168\u4FDD\u5B58</div>\n    <div class=\"links\">\n      <a href=\"https://aistudio.google.com/app/apikey\" target=\"_blank\">\u83B7\u53D6 API Key</a>\n      <a href=\"https://github.com\" target=\"_blank\">\u4F7F\u7528\u5E2E\u52A9</a>\n    </div>\n  </div>\n  <script src=\"popup.js\"></script>\n</body>\n</html>\n";
exports.popupJs = "\ndocument.addEventListener('DOMContentLoaded', () => {\n  const apiKeyInput = document.getElementById('apiKey');\n  const saveBtn = document.getElementById('saveBtn');\n  const status = document.getElementById('status');\n\n  // Load existing key\n  chrome.storage.local.get(['geminiApiKey'], (result) => {\n    if (result.geminiApiKey) {\n      apiKeyInput.value = result.geminiApiKey;\n    }\n  });\n\n  // Save key\n  saveBtn.addEventListener('click', () => {\n    const key = apiKeyInput.value.trim();\n    chrome.storage.local.set({ geminiApiKey: key }, () => {\n      status.style.display = 'block';\n      setTimeout(() => {\n        status.style.display = 'none';\n      }, 2000);\n    });\n  });\n\n  // Open History\n  document.getElementById('historyBtn').addEventListener('click', () => {\n    chrome.tabs.create({ url: 'collection.html' });\n  });\n});\n";
exports.collectionHtml = "\n<!DOCTYPE html>\n<html>\n<head>\n  <meta charset=\"UTF-8\">\n  <title>\u63D0\u793A\u8BCD\u6536\u85CF\u5939</title>\n  <style>\n    body { font-family: -apple-system, BlinkMacSystemFont, \"Segoe UI\", Roboto, Helvetica, Arial, sans-serif; background: #09090b; color: #e4e4e7; margin: 0; padding: 40px; min-height: 100vh; }\n    .header { display: flex; align-items: center; justify-content: space-between; margin-bottom: 40px; max-width: 1200px; margin-left: auto; margin-right: auto; }\n    .header-actions { display: flex; gap: 12px; }\n    .header h1 { margin: 0; font-size: 28px; display: flex; align-items: center; gap: 12px; font-weight: 800; }\n    .btn-action { background: rgba(255,255,255,0.05); color: #e4e4e7; border: 1px solid rgba(255,255,255,0.1); padding: 10px 20px; border-radius: 12px; cursor: pointer; font-weight: 700; transition: all 0.2s; }\n    .btn-action:hover { background: rgba(255,255,255,0.1); transform: translateY(-2px); }\n    .clear-btn { background: rgba(239, 68, 68, 0.1); color: #ef4444; border: 1px solid rgba(239, 68, 68, 0.2); padding: 10px 20px; border-radius: 12px; cursor: pointer; font-weight: 700; transition: all 0.2s; }\n    .clear-btn:hover { background: rgba(239, 68, 68, 0.2); transform: translateY(-2px); }\n    .search-input { background: rgba(255,255,255,0.05); border: 1px solid rgba(255,255,255,0.1); padding: 10px 20px; border-radius: 12px; color: #fff; width: 240px; }\n    .grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(220px, 1fr)); gap: 20px; max-width: 1200px; margin: 0 auto; }\n    .table-view { width: 100%; max-width: 1200px; margin: 0 auto; border-collapse: collapse; background: rgba(255,255,255,0.03); border-radius: 24px; overflow: hidden; }\n    .table-view th, .table-view td { padding: 20px; text-align: left; border-bottom: 1px solid rgba(255,255,255,0.05); }\n    .table-view th { color: #71717a; font-size: 12px; text-transform: uppercase; }\n    .table-img { width: 60px; height: 80px; object-fit: cover; border-radius: 8px; }\n    .card { background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.08); border-radius: 20px; overflow: hidden; display: flex; flex-direction: column; transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1); backdrop-filter: blur(20px); }\n    .card:hover { border-color: rgba(139, 92, 246, 0.4); box-shadow: 0 12px 40px rgba(0,0,0,0.5), 0 0 30px rgba(139, 92, 246, 0.15); transform: translateY(-6px); }\n    .card-img { width: 100%; aspect-ratio: 3 / 4; height: auto; object-fit: cover; background: #18181b; border-bottom: 1px solid rgba(255,255,255,0.05); }\n    .card-content { padding: 16px; flex: 1; display: flex; flex-direction: column; }\n    .time { font-size: 12px; color: #71717a; margin-bottom: 16px; font-weight: 600; }\n    .actions { display: flex; gap: 12px; margin-top: auto; }\n    .btn { flex: 1; padding: 12px; border-radius: 12px; border: none; cursor: pointer; font-weight: 700; font-size: 13px; transition: all 0.2s; display: flex; align-items: center; justify-content: center; gap: 6px; white-space: nowrap; }\n    .btn-copy { background: #fff; color: #000; }\n    .btn-copy:hover { background: #e4e4e7; transform: translateY(-2px); }\n    .btn-replace { background: rgba(52, 211, 153, 0.1); color: #34d399; border: 1px solid rgba(52, 211, 153, 0.2); }\n    .btn-replace:hover { background: rgba(52, 211, 153, 0.2); transform: translateY(-2px); }\n    .btn-copy-mod { background: rgba(139, 92, 246, 0.1); color: #a78bfa; border: 1px solid rgba(139, 92, 246, 0.2); }\n    .btn-copy-mod:hover { background: rgba(139, 92, 246, 0.2); transform: translateY(-2px); }\n    .btn-del { background: rgba(255,255,255,0.05); color: #e4e4e7; border: 1px solid rgba(255,255,255,0.1); }\n    .btn-del:hover { background: rgba(239, 68, 68, 0.2); color: #ef4444; border-color: rgba(239, 68, 68, 0.3); transform: translateY(-2px); }\n    .empty { text-align: center; padding: 120px 0; color: #71717a; grid-column: 1 / -1; background: rgba(255,255,255,0.02); border-radius: 32px; border: 1px dashed rgba(255,255,255,0.05); }\n    .empty h2 { color: #e4e4e7; margin-bottom: 8px; }\n  </style>\n</head>\n<body>\n  <div class=\"header\">\n    <h1>\uD83E\uDD86 \u63D0\u793A\u8BCD\u6536\u85CF\u5939</h1>\n    <div class=\"header-actions\">\n      <input type=\"text\" id=\"search\" class=\"search-input\" placeholder=\"\u641C\u7D22\u5173\u952E\u8BCD...\">\n      <button class=\"btn-action\" id=\"exportBtn\">\u5BFC\u51FA CSV</button>\n      <button class=\"clear-btn\" id=\"clearAll\">\u6E05\u7A7A\u5168\u90E8\u8BB0\u5F55</button>\n    </div>\n  </div>\n  <div class=\"grid\" id=\"grid\"></div>\n  <table class=\"table-view\" id=\"tableView\" style=\"display:none;\">\n    <thead><tr><th>\u56FE\u7247</th><th>\u5173\u952E\u8BCD</th></tr></thead>\n    <tbody id=\"tableBody\"></tbody>\n  </table>\n  <script src=\"collection.js\"></script>\n</body>\n</html>\n";
exports.collectionJs = "\ndocument.addEventListener('DOMContentLoaded', () => {\n  const grid = document.getElementById('grid');\n  const tableView = document.getElementById('tableView');\n  const tableBody = document.getElementById('tableBody');\n  const clearBtn = document.getElementById('clearAll');\n  const searchInput = document.getElementById('search');\n  const exportBtn = document.getElementById('exportBtn');\n  \n  let historyData = [];\n  let isGridView = true;\n\n  function render() {\n    chrome.storage.local.get(['promptHistory'], (result) => {\n      const allData = result.promptHistory || [];\n      const searchTerm = searchInput.value.toLowerCase();\n      historyData = allData.filter(item => {\n        const d = item.data.zh;\n        const keywords = Object.values(d).join(' ').toLowerCase();\n        return keywords.includes(searchTerm);\n      });\n\n      if (historyData.length === 0) {\n        grid.innerHTML = '<div class=\"empty\"><h2>\u6682\u65E0\u6536\u85CF\u8BB0\u5F55</h2><p>\u5728\u7F51\u9875\u4E0A\u63D0\u53D6\u7684\u63D0\u793A\u8BCD\u4F1A\u81EA\u52A8\u4FDD\u5B58\u5728\u8FD9\u91CC\uFF08\u5B58\u50A8\u4E8E\u6D4F\u89C8\u5668\u672C\u5730\u7F13\u5B58\uFF09</p></div>';\n        tableView.style.display = 'none';\n        clearBtn.style.display = 'none';\n        return;\n      }\n      \n      clearBtn.style.display = 'block';\n      \n      if (isGridView) {\n        grid.style.display = 'grid';\n        tableView.style.display = 'none';\n        grid.innerHTML = '';\n        historyData.forEach(item => {\n          const d = item.data.zh || item.data;\n          const hasModified = !!item.modifiedPrompt;\n          const card = document.createElement('div');\n          card.className = 'card';\n          card.innerHTML = `\n            <img src=\"${item.url}\" class=\"card-img\" onerror=\"this.src='data:image/svg+xml;base64,'\">\n            <div class=\"card-content\">\n              <div class=\"time\">${new Date(item.timestamp).toLocaleString()}</div>\n              <div class=\"actions\" style=\"display: flex; flex-wrap: wrap; gap: 8px;\">\n                ${hasModified ? `\n                  <button class=\"btn btn-copy\" data-id=\"${item.id}\" style=\"flex: 1;\">\u590D\u5236\u539F\u63D0\u793A\u8BCD</button>\n                  <button class=\"btn btn-copy-mod\" data-id=\"${item.id}\" style=\"flex: 1;\">\u590D\u5236\u4FEE\u6539\u540E</button>\n                ` : `\n                  <button class=\"btn btn-copy\" data-id=\"${item.id}\" style=\"flex: 1;\">\u590D\u5236\u63D0\u793A\u8BCD</button>\n                  <button class=\"btn btn-replace\" data-id=\"${item.id}\" style=\"flex: 1;\">\u66FF\u6362\u4E3B\u4F53</button>\n                `}\n                <button class=\"btn btn-del\" data-id=\"${item.id}\" style=\"flex: 1 1 100%;\">\u5220\u9664</button>\n              </div>\n            </div>\n          `;\n          grid.appendChild(card);\n        });\n      } else {\n        grid.style.display = 'none';\n        tableView.style.display = 'table';\n        tableBody.innerHTML = '';\n        historyData.forEach(item => {\n          const d = item.data.zh || item.data;\n          const keywords = Object.keys(d).filter(k => k.startsWith('part')).map(k => d[k]).join(' ');\n          const row = document.createElement('tr');\n          row.innerHTML = `\n            <td><img src=\"${item.url}\" class=\"table-img\"></td>\n            <td>${keywords.substring(0, 100)}...</td>\n          `;\n          tableBody.appendChild(row);\n        });\n      }\n\n      // Bind events\n      document.querySelectorAll('.btn-copy').forEach(btn => {\n        btn.addEventListener('click', (e) => {\n          const id = parseInt(e.currentTarget.dataset.id);\n          const item = historyData.find(x => x.id === id);\n          if (item) {\n            const d = item.data.zh || item.data;\n            const text = Object.keys(d).filter(k => k.startsWith('part')).map(k => d[k]).join(', ');\n            navigator.clipboard.writeText(text);\n            const originalText = e.currentTarget.innerText;\n            e.currentTarget.innerText = '\u5DF2\u590D\u5236!';\n            setTimeout(() => e.currentTarget.innerText = originalText, 2000);\n          }\n        });\n      });\n\n      document.querySelectorAll('.btn-copy-mod').forEach(btn => {\n        btn.addEventListener('click', (e) => {\n          const id = parseInt(e.currentTarget.dataset.id);\n          const item = historyData.find(x => x.id === id);\n          if (item && item.modifiedPrompt) {\n            navigator.clipboard.writeText(item.modifiedPrompt);\n            const originalText = e.currentTarget.innerText;\n            e.currentTarget.innerText = '\u5DF2\u590D\u5236!';\n            setTimeout(() => e.currentTarget.innerText = originalText, 2000);\n          }\n        });\n      });\n\n      document.querySelectorAll('.btn-replace').forEach(btn => {\n        btn.addEventListener('click', (e) => {\n          const id = parseInt(e.currentTarget.dataset.id);\n          const item = historyData.find(x => x.id === id);\n          if (item) {\n            const d = item.data.zh || item.data;\n            const originalPrompt = Object.keys(d).filter(k => k.startsWith('part')).map(k => d[k]).join(', ');\n            \n            e.currentTarget.innerText = '\u5904\u7406\u4E2D...';\n            e.currentTarget.disabled = true;\n            \n            chrome.runtime.sendMessage({ action: 'rewritePrompt', prompt: originalPrompt }, (response) => {\n              if (response && response.data) {\n                chrome.storage.local.get(['promptHistory'], (res) => {\n                  const newHistory = (res.promptHistory || []).map(x => {\n                    if (x.id === id) {\n                      return { ...x, modifiedPrompt: response.data };\n                    }\n                    return x;\n                  });\n                  chrome.storage.local.set({ promptHistory: newHistory }, render);\n                });\n              } else {\n                alert('\u66FF\u6362\u5931\u8D25: ' + (response?.error || '\u672A\u77E5\u9519\u8BEF'));\n                e.currentTarget.innerText = '\u66FF\u6362\u4E3B\u4F53';\n                e.currentTarget.disabled = false;\n              }\n            });\n          }\n        });\n      });\n\n      document.querySelectorAll('.btn-del').forEach(btn => {\n        btn.addEventListener('click', (e) => {\n          const id = parseInt(e.currentTarget.dataset.id);\n          chrome.storage.local.get(['promptHistory'], (res) => {\n            const newHistory = (res.promptHistory || []).filter(x => x.id !== id);\n            chrome.storage.local.set({ promptHistory: newHistory }, render);\n          });\n        });\n      });\n    });\n  }\n\n  searchInput.addEventListener('input', render);\n  \n  exportBtn.addEventListener('click', () => {\n    chrome.storage.local.get(['promptHistory'], (res) => {\n      const history = res.promptHistory || [];\n      if (history.length === 0) return;\n      \n      const headers = ['\u65F6\u95F4', '\u56FE\u7247URL', '\u5B8C\u6574\u63D0\u793A\u8BCD'];\n      const rows = history.map(item => {\n        const d = item.data.zh || item.data; // Handle both Gemini and Ollama data structures\n        const fullPrompt = [d.part1, d.part2, d.part3, d.part4, d.part5, d.part6, d.part7, d.part8, d.part9].filter(Boolean).join('\\n');\n        return [\n          new Date(item.timestamp).toLocaleString(),\n          item.url,\n          `\"${fullPrompt.replace(/\"/g, '\"\"')}\"`\n        ].join(',');\n      });\n      \n      const csvContent = \"\\uFEFF\" + [headers.join(','), ...rows].join('\\n');\n      const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });\n      const url = URL.createObjectURL(blob);\n      const link = document.createElement('a');\n      link.setAttribute('href', url);\n      link.setAttribute('download', `ai_prompts_export_${new Date().getTime()}.csv`);\n      link.style.visibility = 'hidden';\n      document.body.appendChild(link);\n      link.click();\n      document.body.removeChild(link);\n    });\n  });\n\n  clearBtn.addEventListener('click', () => {\n    if (confirm('\u786E\u5B9A\u8981\u6E05\u7A7A\u6240\u6709\u6536\u85CF\u8BB0\u5F55\u5417\uFF1F\u6B64\u64CD\u4F5C\u4E0D\u53EF\u6062\u590D\u3002')) {\n      chrome.storage.local.set({ promptHistory: [] }, render);\n    }\n  });\n\n  render();\n});\n";
exports.sidepanelHtml = "\n<!DOCTYPE html>\n<html>\n<head>\n  <meta charset=\"UTF-8\">\n  <title>AI \u526F\u9A7E\u9A76</title>\n  <style>\n    body { font-family: -apple-system, BlinkMacSystemFont, \"Segoe UI\", Roboto, sans-serif; height: 100vh; display: flex; flex-direction: column; margin: 0; background: #09090b; color: #e4e4e7; }\n    #nav { padding: 8px; border-bottom: 1px solid #27272a; display: flex; gap: 8px; }\n    .tab { padding: 6px 12px; cursor: pointer; border-radius: 4px; }\n    .tab.active { background: #27272a; }\n    #content { flex: 1; overflow-y: auto; padding: 12px; }\n    #action-bar { padding: 12px; border-top: 1px solid #27272a; background: #18181b; }\n    #prompt-input { width: 100%; padding: 8px; border-radius: 6px; border: 1px solid #27272a; background: #09090b; color: white; margin-bottom: 8px; box-sizing: border-box; }\n    .btn { padding: 8px 16px; border-radius: 6px; cursor: pointer; border: none; font-weight: 500; }\n    .btn-primary { background: #3b82f6; color: white; }\n    .hidden { display: none; }\n  </style>\n</head>\n<body>\n  <div id=\"nav\">\n    <div class=\"tab active\" data-tab=\"library\">\u7075\u611F\u5E93</div>\n    <div class=\"tab\" data-tab=\"chat\">Chat</div>\n  </div>\n  <div id=\"content\">\n    <div id=\"library-view\"></div>\n    <div id=\"chat-view\" class=\"hidden\"></div>\n  </div>\n  <div id=\"action-bar\">\n    <textarea id=\"prompt-input\" rows=\"3\" placeholder=\"\u8F93\u5165\u6216\u4FEE\u6539\u63D0\u793A\u8BCD...\"></textarea>\n    <div style=\"display: flex; gap: 8px;\">\n      <button class=\"btn btn-primary\" id=\"inject-btn\" style=\"flex: 1;\">\u6CE8\u5165\u5230\u7F51\u9875</button>\n      <button class=\"btn\" id=\"optimize-btn\" style=\"flex: 1;\">\u667A\u80FD\u4F18\u5316</button>\n    </div>\n  </div>\n  <script src=\"sidepanel.js\"></script>\n</body>\n</html>\n";
exports.sidepanelJs = "\nconst tabs = document.querySelectorAll('.tab');\nconst views = { library: document.getElementById('library-view'), chat: document.getElementById('chat-view') };\nconst promptInput = document.getElementById('prompt-input');\n\ntabs.forEach(tab => {\n  tab.addEventListener('click', () => {\n    tabs.forEach(t => t.classList.remove('active'));\n    tab.classList.add('active');\n    Object.values(views).forEach(v => v.classList.add('hidden'));\n    views[tab.dataset.tab].classList.remove('hidden');\n  });\n});\n\n// Render Library\nfunction renderLibrary() {\n  const libraryView = views.library;\n  libraryView.innerHTML = '';\n  chrome.storage.local.get(['promptHistory'], (res) => {\n    const history = res.promptHistory || [];\n    history.forEach(item => {\n      const card = document.createElement('div');\n      card.style.cssText = 'padding: 8px; border: 1px solid #27272a; border-radius: 6px; margin-bottom: 8px; cursor: pointer;';\n      const d = item.data.zh || item.data;\n      const keywords = Object.keys(d).filter(k => k.startsWith('part')).map(k => d[k]).join(' ');\n      card.innerHTML = `<img src=\"${item.url}\" style=\"width: 100%; height: 100px; object-fit: cover; border-radius: 4px;\">\n                        <div style=\"font-size: 12px; margin-top: 4px; overflow: hidden; text-overflow: ellipsis; display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical;\">${keywords}</div>`;\n      card.onclick = () => { promptInput.value = keywords; };\n      libraryView.appendChild(card);\n    });\n  });\n}\n\n// Chat Logic\nconst chatView = views.chat;\nchatView.innerHTML = `<div id=\"chat-messages\" style=\"height: 300px; overflow-y: auto; margin-bottom: 8px;\"></div>\n                      <div style=\"display: flex; gap: 4px;\">\n                        <input id=\"chat-input\" style=\"flex: 1; padding: 4px; border-radius: 4px; border: 1px solid #27272a; background: #09090b; color: white;\">\n                        <button id=\"send-btn\" class=\"btn btn-primary\">\u53D1\u9001</button>\n                      </div>`;\n\nconst chatMessages = document.getElementById('chat-messages');\nconst chatInput = document.getElementById('chat-input');\ndocument.getElementById('send-btn').addEventListener('click', () => {\n  const msg = chatInput.value;\n  if (!msg) return;\n  chatMessages.innerHTML += `<div style=\"text-align: right; margin-bottom: 4px;\">${msg}</div>`;\n  chatInput.value = '';\n  chrome.runtime.sendMessage({ action: 'chat', message: msg, context: promptInput.value }, (response) => {\n    if (response && response.data) {\n      chatMessages.innerHTML += `<div style=\"text-align: left; margin-bottom: 4px; color: #3b82f6;\">${response.data}</div>`;\n    }\n  });\n});\n\ndocument.getElementById('inject-btn').addEventListener('click', () => {\n  chrome.tabs.query({active: true, currentWindow: true}, (tabs) => {\n    chrome.scripting.executeScript({\n      target: {tabId: tabs[0].id},\n      func: (prompt) => {\n        const activeElement = document.activeElement;\n        if (activeElement && (activeElement.tagName === 'TEXTAREA' || activeElement.tagName === 'INPUT')) {\n          activeElement.value = prompt;\n        }\n      },\n      args: [promptInput.value]\n    });\n  });\n});\n\ndocument.getElementById('optimize-btn').addEventListener('click', () => {\n  chrome.runtime.sendMessage({ action: 'smartOptimize', prompt: promptInput.value }, (response) => {\n    if (response && response.data) {\n      promptInput.value = response.data;\n    }\n  });\n});\n\nrenderLibrary();\n";
